import{_ as e,c as s,a as n,o as t}from"./app-6Yjp8K1A.js";const c={};function r(o,a){return t(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="react-性能优化清单" tabindex="-1"><a class="header-anchor" href="#react-性能优化清单"><span>React 性能优化清单</span></a></h1><h2 id="_1-先定位-再优化" tabindex="-1"><a class="header-anchor" href="#_1-先定位-再优化"><span>1. 先定位，再优化</span></a></h2><p>性能优化的第一原则不是“加缓存”，而是先找出真正的性能瓶颈。优先用 React DevTools Profiler 看哪些组件重复渲染。</p><h2 id="_2-控制不必要渲染" tabindex="-1"><a class="header-anchor" href="#_2-控制不必要渲染"><span>2. 控制不必要渲染</span></a></h2><p>常见手段包括：</p><ul><li><code>React.memo</code></li><li><code>useMemo</code></li><li><code>useCallback</code></li><li>状态下沉或拆分组件</li></ul><h2 id="_3-列表渲染要稳定" tabindex="-1"><a class="header-anchor" href="#_3-列表渲染要稳定"><span>3. 列表渲染要稳定</span></a></h2><p>长列表场景优先关注两点：</p><ul><li><code>key</code> 是否稳定</li><li>是否需要虚拟列表</li></ul><h2 id="_4-避免把所有状态都放到顶层" tabindex="-1"><a class="header-anchor" href="#_4-避免把所有状态都放到顶层"><span>4. 避免把所有状态都放到顶层</span></a></h2><p>过大的状态作用域会导致更多组件联动更新。把状态尽量放到真正使用它的地方。</p><h2 id="_5-异步加载与代码分割" tabindex="-1"><a class="header-anchor" href="#_5-异步加载与代码分割"><span>5. 异步加载与代码分割</span></a></h2><p>路由级别和组件级别都可以做懒加载：</p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token keyword">const</span> UserPage <span class="token operator">=</span> React<span class="token punctuation">.</span><span class="token function">lazy</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token keyword">import</span><span class="token punctuation">(</span><span class="token string">&#39;./UserPage&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结"><span>总结</span></a></h2><p>React 优化不等于 everywhere memo。真正有效的优化路径是：测量、定位、拆分、缓存、懒加载。</p>`,16)])])}const l=e(c,[["render",r]]),i=JSON.parse('{"path":"/posts/react-performance-checklist.html","title":"React 性能优化清单","lang":"zh-CN","frontmatter":{},"git":{"updatedTime":1773394873000,"contributors":[{"name":"wulr","username":"wulr","email":"wulr@eastcom-sw.com","commits":1,"url":"https://github.com/wulr"}],"changelog":[{"hash":"2e05be3a6e915f9542c6b5a3b229ee576fde38ba","time":1773394873000,"email":"wulr@eastcom-sw.com","author":"wulr","message":"Remove spaces from MD filenames and update references"}]},"filePathRelative":"posts/react-performance-checklist.md"}');export{l as comp,i as data};
